var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"아버지는 변덕스러웠다.","JPN":"父さんは気まぐれだった。","ENG":"Dad was a fickle being.","TWN":"爸爸總是喜怒無常。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"호탕하게 웃다가도 눈에 거슬리는 것이 보이면 바로 손찌검이 날아왔다.","JPN":"豪快に笑っていても、気に障るものがあればすぐに手が出た。","ENG":"He would be laughing one second, then be fuming mad the next and start hitting me.","TWN":"明明笑得很開心，但只要看到什麼不順眼的事，就會立刻一陣拳打腳踢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"언제부터인가 사람이 무서워졌다.","JPN":"いつからか人が怖くなった。","ENG":"At some point, this led me to become scared of people.","TWN":"不知道從何時開始，我變得很怕人。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"다들, 아버지처럼 돌변할 것 같아서.","JPN":"みんな、父さんみたいに急変しそうで。","ENG":"Because... I thought everyone would change moods just like Dad.","TWN":"因為我怕他們會像爸爸一樣，說翻臉就翻臉。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_MASK","text":{"KOREA":"이겨야 돼… 이겨야…….","JPN":"勝たなきゃ……勝たなきゃ……","ENG":"Win... I have to win...","TWN":"我必須要贏…要贏……"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_MASK","text":{"KOREA":"헤이븐은 최강 최흉, 이렇게 쓰러지면 안 돼……!","JPN":"ヘイブンは最強で最凶、このまま倒れちゃダメだ……！","ENG":"\\"Haven\\" is the strongest and most villainous! I can't be defeated like this...!","TWN":"天堂是最強悍、最兇狠的，不能就這樣倒下……！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"친구들이 걱정되어서 네 몸을 상하게 하는 거라면 그만둬.","JPN":"みんなが心配で自分を傷つけるつもりならやめときな。","ENG":"If you're hurting yourself because you're worried about your friends, you should stop.","TWN":"不要因為擔心朋友，而做出傷害自己身體的事。"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_SERIOUS2"}}}},{"id":"L11_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"네가 네 친구에게 만들어 달라고 했던 다리야. 못 믿는 건 아니겠지?","JPN":"あんたが友達に頼んで作ってもらった足だろ。信じられないわけじゃないよな？","ENG":"You don't believe me? These are the legs you asked your friends to make for me.","TWN":"這是你請你朋友做的腳，應該信得過吧？"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_SERIOUS2"}}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_MASK","text":{"KOREA":"상대는 허드슨이나 호란이 아니라 헤론이야. 분명 무슨 함정을 파 뒀을 거라고.","JPN":"相手はハドソンとホランじゃなくてヘロンだよ。きっと何か罠があるはずなんだ。","ENG":"Your enemy is not Hudson or Horan. It's Heron. I'm certain she's setting you up for something.","TWN":"對方不是哈德森或小蘭，是海倫。她一定有設下什麼陷阱。"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"10초, 아니. 1초만 줘도 쟤들한테 갈 수 있어.","JPN":"10秒、いや。1秒くれればみんなのところに行ける。","ENG":"Just give me 10 seconds, no, 1 second and I'll be able to reach them.","TWN":"給我10秒，不，1秒就好，我可以立刻衝去找她們。"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이 대결이 어떻게 결판 나든, 친구들은 무사히 풀어 줄 거야.","JPN":"この対決の結果がどうなっても、友達は無事助けるよ。","ENG":"No matter the outcome of this match, I will free my friends.","TWN":"無論這場比賽的勝負如何，我都會替她們解開繩子！"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_MASK","text":{"KOREA":"그, 그렇다면……!","JPN":"そ、それなら……！","ENG":"Th-then...!","TWN":"既然如此……！"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아아, 믿을 수가 없군요!</color>","JPN":"<color=#ffd34c>ああ、信じられません！</color>","ENG":"<color=#ffd34c>I can't believe it!</color>","TWN":"<color=#ffd34c>哇，真不敢置信！</color>"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이게 어떻게 된 건가요! 헤이븐 형님이 밀리고 계십니다!</color>","JPN":"<color=#ffd34c>これはどういうことでしょうか！　ヘイブン様が押されてます！</color>","ENG":"<color=#ffd34c>What is going on?! Mr. Haven is being pushed back!</color>","TWN":"<color=#ffd34c>這是怎麼回事？天堂大哥現在有點落後！</color>"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>어리석은 도전자들에게 기권할 기회를 주시려는 걸까요?! 형님의 속내를 모르겠습니다!</color>","JPN":"<color=#ffd34c>愚かな挑戦者たちに棄権する機会を与えるつもりなんでしょうか！？　意図がよめません！</color>","ENG":"<color=#ffd34c>Is he giving the challengers a chance to forfeit?! I don't know what he's thinking!</color>","TWN":"<color=#ffd34c>是想給愚蠢的挑戰者棄權的機會嗎？真猜不透大哥呢！</color>"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"저 멍청이가 끝까지…….","JPN":"あのバカ、最後まで……","ENG":"That fool...","TWN":"那個蠢蛋……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};